#!/usr/bin/env python3
import base64, os, sys
if not os.path.isfile("App.js"): sys.exit("Run from BatKnock root")

os.makedirs("screens", exist_ok=True)
with open("screens/ProfileScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/ProfileScreen.js")

with open("App.js", "wb") as f: f.write(base64.b64decode(""))
print("OK App.js")

os.makedirs("screens", exist_ok=True)
with open("screens/HomeScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/HomeScreen.js")

print()
print("Run: npx expo start --clear --lan")
print("Then: Home -> Settings -> Profile")
